      const now = new Date();
      // Expansion window for non-yearly: 1 year back to 1 year ahead
      const windowStart = new Date(now.getFullYear() - 1, now.getMonth(), now.getDate());
      const windowEnd = new Date(now.getFullYear() + 1, now.getMonth(), now.getDate());

